1	export interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	const PROCESSING_FEE = 5;
8	const FIRST_INSURANCE_SURCHARGE = 1.1;
9	const RETURNING_CUSTOMER_DISCOUNT = 0.85;
10	
11	function contractMultiplierFor(previousContracts: number | undefined): number {
12	  return (previousContracts ?? 0) >= 1 ? RETURNING_CUSTOMER_DISCOUNT : FIRST_INSURANCE_SURCHARGE;
13	}
14	
15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	  moonstone: 25,
22	};
23	
24	const COMPONENT_BUNDLE_BASE = 60;
25	const COMPONENT_BUNDLE_SIZE = 3;
26	const BUNDLEABLE_COMPONENTS = new Set(["rune", "moonstone"]);
27	
28	function roundUpToWholeG(amount: number): number {
29	  // Round to cents first to avoid float-precision artifacts like 100*1.10 = 110.00000000000001
30	  return Math.ceil(Math.round(amount * 100) / 100);
31	}
32	
33	const CURSED_SURCHARGE = 1.5;
34	const HIGH_ENCHANTMENT_SURCHARGE = 1.3;
35	const HIGH_ENCHANTMENT_THRESHOLD = 5;
36	
37	const LOYALTY_DISCOUNT = 0.8;
38	const LOYALTY_YEARS_THRESHOLD = 2;
39	
40	function loyaltyDiscountFor(customer: { yearsWithMHPCO: number }): number {
41	  return customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_DISCOUNT : 1;
42	}
43	
44	function isHighlyEnchanted(item: Item): boolean {
45	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
46	}
47	
48	function riskMultiplier(item: Item): number {
49	  const cursedMultiplier = item.cursed ? CURSED_SURCHARGE : 1;
50	  const enchantmentMultiplier = isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE : 1;
51	  return cursedMultiplier * enchantmentMultiplier;
52	}
53	
54	function premiumFor(item: Item, loyaltyDiscount: number, contractMultiplier: number): number {
55	  const basePremium = BASE_PREMIUMS[item.type];
56	  return roundUpToWholeG(basePremium * riskMultiplier(item) * loyaltyDiscount * contractMultiplier);
57	}
58	
59	function isThreeAlikeBundle(items: Item[]): boolean {
60	  if (items.length !== COMPONENT_BUNDLE_SIZE) return false;
61	  const firstType = items[0].type;
62	  return (
63	    BUNDLEABLE_COMPONENTS.has(firstType) &&
64	    items.every((item) => item.type === firstType)
65	  );
66	}
67	
68	function bundlePremium(contractMultiplier: number): number {
69	  return roundUpToWholeG(COMPONENT_BUNDLE_BASE * contractMultiplier);
70	}
71	
72	export function quote(
73	  customer: { yearsWithMHPCO: number },
74	  items: Item[],
75	  previousContracts?: number,
76	): number {
77	  const loyaltyDiscount = loyaltyDiscountFor(customer);
78	  const contractMultiplier = contractMultiplierFor(previousContracts);
79	  const itemsTotal = isThreeAlikeBundle(items)
80	    ? bundlePremium(contractMultiplier)
81	    : items.reduce((sum, item) => sum + premiumFor(item, loyaltyDiscount, contractMultiplier), 0);
82	  return itemsTotal + PROCESSING_FEE;
83	}
84	
85	export function claim(): number {
86	  return undefined as unknown as number;
87	}
